      { "name": "Payment Processor Core", "responsibility": "Executes payment business logic (authorization, capture, settlement)", "boundaries": "Receives already-decrypted payment data; emits domain events; never handles encryption directly" },
      { "name": "Persistent Store", "responsibility": "Stores encrypted payment records (ciphertext + DEK reference + CMK version metadata)", "boundaries": "All data at rest is ciphertext; no plaintext payment data ever hits disk" }
