      { "from": "Payment Gateway", "to": "Crypto Envelope Service", "contract": "decrypt(encryptedPayload, dekRef) → PlaintextPayload; encrypt(plaintext) → (ciphertext, dekRef)", "coupling_type": "synchronous, in-process" },
