      { "from": "Payment Gateway", "to": "Payment Processor Core", "contract": "processPayment(PlaintextPayload) → PaymentResult", "coupling_type": "synchronous, in-process" },
      { "from": "Key Rotation Orchestrator", "to": "Crypto Envelope Service", "contract": "rotateDEK(oldDekRef) → newDekRef; registerDEK(newWrappedDEK)", "coupling_type": "asynchronous, background" },
